const score = {{fatores_infertilidade_score}};

// 2. máximo e função de nível
const max = 72;
function niv(v,m){
  const r = v/m;
  if(r>=0.8)    return 'Alto';
  if(r>=0.6)    return 'Moderado';
                return 'Baixo';
}

// 3. textos por nível
const textByLevel = {
  Alto: {
    i: "Você não apresenta condições clínicas relevantes como endometriose, SOP, doenças autoimunes ou obstruções tubárias. Seu peso corporal também está dentro da faixa ideal, o que favorece a função hormonal e a ovulação.",
    r: "Continue mantendo seus hábitos atuais de alimentação e atividade física."
  },
  Moderado: {
    i: "Você não apresenta obstruções graves ou doenças autoimunes, mas há pequenos pontos de atenção (como idade, SOP leve ou sensibilidade alimentar) que podem afetar sua fertilidade sem sintomas claros.",
    r: "Acompanhamento clínico regular + dieta anti-inflamatória para blindar esse pilar."
  },
  Baixo: {
    i: "Vários marcadores alterados – como idade elevada, diagnósticos confirmados (SOP, endometriose) ou IMC fora da faixa ideal.",
    r: "Reavaliação com especialista em reprodução + abordagem integrativa com endocrinologista e nutricionista funcional."
  }
};

// 4. determina nível, busca texto e retorna SÓ a string
const nivel = niv(score, max);
const { i, r } = textByLevel[nivel];
return `${i}\n\n` +
       `*Recomendação:* ${r}`;

